    14→const CHAT_EXAMPLES = [
    15→  'Send me a Slack alert when I get a new Stripe payment',
    16→  'Save new Gmail leads to a Google Sheet daily',
    17→  'Post to Instagram when I publish a new blog post',
    18→  'Alert me when a form is submitted on my website',
