    21→function extractChatJson(text) {
    22→  const block = text.match(/```json\s*([\s\S]*?)```/);
    23→  if (block) return block[1].trim();
    24→  const loose = text.match(/(\{[\s\S]*\})/);
    25→  return loose ? loose[1].trim() : null;
    26→}
