    28→function downloadJson(json, filename = 'n8n-workflow.json') {
    29→  const blob = new Blob([json], { type: 'application/json' });
    30→  const url = URL.createObjectURL(blob);
    31→  const a = document.createElement('a');
    32→  a.href = url;
    33→  a.download = filename;
    34→  a.click();
    35→  URL.revokeObjectURL(url);
    36→}
