    38→function N8nChat({ tool, currentUser }) {
    39→  const [messages, setMessages] = useState([
    40→    { role: 'assistant', text: "Hi! Tell me what you want to automate and I'll build it for you. For example: \"Send me a Slack message when I get a new lead.\"" },
    41→  ]);
    42→  const [input, setInput] = useState('');
    43→  const [loading, setLoading] = useState(false);
    44→  const bottomRef = useRef(null);
    45→
    46→  useEffect(() => {
    47→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    48→  }, [messages, loading]);
    49→
    50→  async function sendMessage(e) {
    51→    e.preventDefault();
    52→    const text = input.trim();
    53→    if (!text || loading) return;
    54→    setMessages(prev => [...prev, { role: 'user', text }]);
    55→    setInput('');
    56→    setLoading(true);
    57→    try {
    58→      const res = await fetch(tool.webhookUrl, {
    59→        method: 'POST',
    60→        headers: { 'Content-Type': 'application/json' },
    61→        body: JSON.stringify({ chatInput: text, sessionId: currentUser?.uid || 'guest' }),
    62→      });
    63→      const data = await res.json();
    64→      const reply = data?.output || data?.message || data?.text || 'Done! Your automation has been set up.';
    65→      setMessages(prev => [...prev, { role: 'assistant', text: reply }]);
    66→    } catch {
    67→      setMessages(prev => [...prev, { role: 'assistant', text: 'Something went wrong connecting to n8n. Make sure your workflow is active.' }]);
    68→    } finally {
    69→      setLoading(false);
    70→    }
    71→  }
    72→
    73→  return (
    74→    <div className="ai-tool">
    75→      <div className="ai-tool__header">
    76→        <div className="ai-tool__title-row">
    77→          <span className="ai-tool__icon">{tool.icon}</span>
    78→          <div>
    79→            <h2 className="ai-tool__title">{tool.name}</h2>
    80→            <p className="ai-tool__description">{tool.description}</p>
    81→          </div>
    82→        </div>
    83→      </div>
    84→
    85→      <div className="n8n-chat">
    86→        <div className="n8n-chat__messages">
    87→          {messages.map((msg, i) => {
    88→            const json = msg.role === 'assistant' ? extractChatJson(msg.text) : null;
    89→            return (
    90→              <div key={i} className={`n8n-chat__msg n8n-chat__msg--${msg.role}`}>
    91→                {msg.role === 'assistant' && <div className="n8n-chat__avatar">⚡</div>}
    92→                <div className="n8n-chat__msg-content">
    93→                  <div className="n8n-chat__bubble">{msg.text}</div>
    94→                  {json && (
    95→                    <button
    96→                      className="n8n-chat__download"
    97→                      onClick={() => downloadJson(json)}
    98→                    >
    99→                      ⬇️ Download JSON
   100→                    </button>
   101→                  )}
   102→                </div>
   103→              </div>
   104→            );
   105→          })}
   106→          {loading && (
   107→            <div className="n8n-chat__msg n8n-chat__msg--assistant">
   108→              <div className="n8n-chat__avatar">⚡</div>
   109→              <div className="n8n-chat__bubble n8n-chat__bubble--typing">
   110→                <span /><span /><span />
   111→              </div>
   112→            </div>
   113→          )}
   114→          <div ref={bottomRef} />
   115→        </div>
   116→
   117→        <div className="n8n-chat__examples">
   118→          {CHAT_EXAMPLES.map(ex => (
   119→            <button key={ex} className="n8n-chat__chip" onClick={() => setInput(ex)} disabled={loading}>
   120→              {ex}
   121→            </button>
   122→          ))}
   123→        </div>
   124→
   125→        <form className="n8n-chat__input-row" onSubmit={sendMessage}>
   126→          <input
   127→            className="n8n-chat__input"
   128→            type="text"
   129→            placeholder="Tell me what you want to automate…"
   130→            value={input}
   131→            onChange={e => setInput(e.target.value)}
   132→            disabled={loading}
   133→          />
   134→          <button className="n8n-chat__send" type="submit" disabled={!input.trim() || loading}>
   135→            Send
   136→          </button>
   137→        </form>
   138→      </div>
   139→    </div>
   140→  );
   141→}
