   143→function FormField({ field, value, onChange, toolId }) {
   144→  const { t } = useTranslation();
   145→  const label = t(`input.${toolId}.${field.id}.label`, { defaultValue: field.label });
   146→  const placeholder = t(`input.${toolId}.${field.id}.placeholder`, { defaultValue: field.placeholder || '' });
   147→
   148→  const commonProps = {
   149→    id: field.id,
   150→    value: value || '',
   151→    onChange: (e) => onChange(field.id, e.target.value),
   152→    placeholder,
   153→    required: field.required,
   154→  };
   155→
   156→  if (field.type === 'textarea') {
   157→    return (
   158→      <div className="form-group">
   159→        <label className="form-label" htmlFor={field.id}>
   160→          {label}
   161→          {field.required && <span className="required-mark"> *</span>}
   162→        </label>
   163→        <textarea className="form-textarea" rows={4} {...commonProps} />
   164→      </div>
   165→    );
   166→  }
   167→
   168→  if (field.type === 'select') {
   169→    return (
   170→      <div className="form-group">
   171→        <label className="form-label" htmlFor={field.id}>
   172→          {label}
   173→          {field.required && <span className="required-mark"> *</span>}
   174→        </label>
   175→        <select className="form-select" {...commonProps}>
   176→          <option value="">{t('ui.selectOption', { defaultValue: 'Select an option...' })}</option>
   177→          {field.options.map((opt) => (
   178→            <option key={opt} value={opt}>{opt}</option>
   179→          ))}
   180→        </select>
   181→      </div>
   182→    );
   183→  }
   184→
   185→  if (field.type === 'multiselect') {
   186→    const selected = value ? value.split(', ').filter(Boolean) : [];
   187→    return (
   188→      <div className="form-group">
   189→        <label className="form-label">
   190→          {label}
   191→          {field.required && <span className="required-mark"> *</span>}
   192→        </label>
   193→        <div className="form-multiselect">
   194→          {field.options.map((opt) => {
   195→            const checked = selected.includes(opt);
   196→            return (
   197→              <label key={opt} className={`form-multiselect__option${checked ? ' form-multiselect__option--checked' : ''}`}>
   198→                <input
   199→                  type="checkbox"
   200→                  checked={checked}
   201→                  onChange={(e) => {
   202→                    const next = e.target.checked
   203→                      ? [...selected, opt]
   204→                      : selected.filter((o) => o !== opt);
   205→                    onChange(field.id, next.join(', '));
   206→                  }}
   207→                />
   208→                <span>{opt}</span>
   209→              </label>
   210→            );
   211→          })}
   212→        </div>
   213→      </div>
   214→    );
   215→  }
   216→
   217→  return (
   218→    <div className="form-group">
   219→      <label className="form-label" htmlFor={field.id}>
   220→        {label}
   221→        {field.required && <span className="required-mark"> *</span>}
   222→      </label>
   223→      <input type="text" className="form-input" {...commonProps} />
   224→    </div>
   225→  );
   226→}
