   228→export default function AIToolInterface({ tool, categoryId }) {
   229→  const [inputs, setInputs] = useState({});
   230→  const [output, setOutput] = useState('');
   231→  const [isStreaming, setIsStreaming] = useState(false);
   232→  const [error, setError] = useState('');
   233→  const [copied, setCopied] = useState(false);
   234→  const [wordCount, setWordCount] = useState(0);
   235→  const outputRef = useRef(null);
   236→  const outputPanelRef = useRef(null);
   237→  const abortControllerRef = useRef(null);
   238→  const finalOutputRef = useRef('');
   239→  const [history, setHistory] = useState([]);
   240→  const [historyOpen, setHistoryOpen] = useState(false);
   241→  const [templates, setTemplates] = useState([]);
   242→  const [templatesOpen, setTemplatesOpen] = useState(false);
   243→  const [showSaveTemplate, setShowSaveTemplate] = useState(false);
   244→  const [templateName, setTemplateName] = useState('');
   245→  const [savingTemplate, setSavingTemplate] = useState(false);
   246→  const [generatedImage, setGeneratedImage] = useState(null);
   247→  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
   248→  const [imageError, setImageError] = useState('');
   249→  const [outputMode, setOutputMode] = useState('image'); // 'image' | 'prompt'
   250→  const [refImage, setRefImage] = useState(null); // { dataUrl, b64, mime, name }
   251→  const refImageInputRef = useRef(null);
   252→
   253→  const { currentUser } = useAuth();
   254→  const { canUseSpecificTool, trackUsage, subscription } = useSubscription();
   255→  const { t, i18n } = useTranslation();
   256→
   257→  // Reset when tool changes
   258→  useEffect(() => {
   259→    const defaults = {};
   260→    setInputs(defaults);
   261→    setOutput('');
   262→    setError('');
   263→    setIsStreaming(false);
   264→    setGeneratedImage(null);
   265→    setImageError('');
   266→    setOutputMode('image');
   267→    setRefImage(null);
   268→  }, [tool?.id, categoryId]);
   269→
   270→  // Load history when tool changes
   271→  useEffect(() => {
   272→    if (tool?.id) {
   273→      try {
   274→        const stored = localStorage.getItem(`gormaran_history_${tool.id}`);
   275→        setHistory(stored ? JSON.parse(stored) : []);
   276→      } catch {
   277→        setHistory([]);
   278→      }
   279→    }
   280→    setHistoryOpen(false);
   281→  }, [tool?.id]);
   282→
   283→  // Load Firestore templates when tool or user changes
   284→  useEffect(() => {
   285→    setTemplates([]);
   286→    setTemplatesOpen(false);
   287→    setShowSaveTemplate(false);
   288→    setTemplateName('');
   289→    if (tool?.id && currentUser) loadTemplates();
   290→  // eslint-disable-next-line react-hooks/exhaustive-deps
   291→  }, [tool?.id, currentUser?.uid]);
   292→
   293→  // Track word count
   294→  useEffect(() => {
   295→    if (output) {
   296→      setWordCount(output.split(/\s+/).filter(Boolean).length);
   297→    } else {
   298→      setWordCount(0);
   299→    }
   300→  }, [output]);
   301→
   302→  // Auto-scroll output
   303→  useEffect(() => {
   304→    if (outputRef.current && isStreaming) {
   305→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
   306→    }
   307→  }, [output, isStreaming]);
   308→
   309→  function handleInputChange(fieldId, value) {
   310→    setInputs((prev) => ({ ...prev, [fieldId]: value }));
   311→  }
   312→
   313→  function validateInputs() {
   314→    const required = tool.inputs.filter((f) => f.required);
   315→    for (const field of required) {
   316→      if (!inputs[field.id] || inputs[field.id].trim() === '') {
   317→        const fieldLabel = t(`input.${tool.id}.${field.id}.label`, { defaultValue: field.label });
   318→        return `"${fieldLabel}" is required`;
   319→      }
   320→    }
   321→    return null;
   322→  }
   323→
   324→  async function handleGenerate(e) {
   325→    e.preventDefault();
   326→    setError('');
   327→
   328→    if (!currentUser) {
   329→      setError(t('ui.signInRequired', { defaultValue: 'Please sign in or create a free account to use this tool.' }));
   330→      return;
   331→    }
   332→
   333→    if (!canUseSpecificTool(categoryId, tool.id)) {
   334→      setError(t('ui.upgradeRequired', { defaultValue: 'This tool requires an upgrade. Visit the pricing page to see your options.' }));
   335→      return;
   336→    }
   337→
   338→    const validationError = validateInputs();
   339→    if (validationError) {
   340→      setError(validationError);
   341→      return;
   342→    }
   343→
   344→    // imageOnly tools skip text streaming and go straight to image generation
   345→    if (tool.imageOnly) {
   346→      setTimeout(() => outputPanelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
   347→      handleGenerateImage();
   348→      return;
   349→    }
   350→
   351→    // imageOrPrompt tools route based on the selected output mode
   352→    if (tool.imageOrPrompt) {
   353→      setTimeout(() => outputPanelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
   354→      if (outputMode === 'image') {
   355→        handleGenerateImage();
   356→      } else {
   357→        // fall through to streaming below
   358→        setOutput('');
   359→        finalOutputRef.current = '';
   360→        setIsStreaming(true);
   361→        const controller = new AbortController();
   362→        abortControllerRef.current = controller;
   363→        const capturedInputs = { ...inputs };
   364→        await streamAIResponse({
   365→          categoryId,
   366→          toolId: tool.id,
   367→          inputs: { ...inputs, _language: i18n.language },
   368→          signal: controller.signal,
   369→          onChunk: (text) => {
   370→            setOutput((prev) => {
   371→              const next = prev + text;
   372→              finalOutputRef.current = next;
   373→              return next;
   374→            });
   375→          },
   376→          onDone: () => {
   377→            setIsStreaming(false);
   378→            trackUsage();
   379→            saveToHistory(capturedInputs, finalOutputRef.current);
   380→          },
   381→          onError: (msg) => {
   382→            setIsStreaming(false);
   383→            setError(msg);
   384→          },
   385→        });
   386→      }
   387→      return;
   388→    }
   389→
   390→    setOutput('');
   391→    finalOutputRef.current = '';
   392→    setIsStreaming(true);
   393→    const controller = new AbortController();
   394→    abortControllerRef.current = controller;
   395→    setTimeout(() => outputPanelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
   396→    const capturedInputs = { ...inputs };
   397→
   398→    await streamAIResponse({
   399→      categoryId,
   400→      toolId: tool.id,
   401→      inputs: { ...inputs, _language: i18n.language },
   402→      signal: controller.signal,
   403→      onChunk: (text) => {
   404→        setOutput((prev) => {
   405→          const next = prev + text;
   406→          finalOutputRef.current = next;
   407→          return next;
   408→        });
   409→      },
   410→      onDone: () => {
   411→        setIsStreaming(false);
   412→        trackUsage();
   413→        saveToHistory(capturedInputs, finalOutputRef.current);
   414→      },
   415→      onError: (msg) => {
   416→        setIsStreaming(false);
   417→        setError(msg);
   418→      },
   419→    });
   420→  }
   421→
   422→  function handleStop() {
   423→    abortControllerRef.current?.abort();
   424→    setIsStreaming(false);
   425→  }
   426→
   427→  function handleRefImageChange(e) {
   428→    const file = e.target.files?.[0];
   429→    if (!file) return;
   430→    const reader = new FileReader();
   431→    reader.onload = (ev) => {
   432→      const dataUrl = ev.target.result;
   433→      const [header, b64] = dataUrl.split(',');
   434→      const mime = header.match(/:(.*?);/)?.[1] || 'image/jpeg';
   435→      setRefImage({ dataUrl, b64, mime, name: file.name });
   436→      setInputs(prev => ({ ...prev, _ref_image_b64: b64, _ref_image_mime: mime }));
   437→    };
   438→    reader.readAsDataURL(file);
   439→  }
   440→
   441→  function handleRemoveRefImage() {
   442→    setRefImage(null);
   443→    setInputs(prev => {
   444→      const next = { ...prev };
   445→      delete next._ref_image_b64;
   446→      delete next._ref_image_mime;
   447→      return next;
   448→    });
   449→    if (refImageInputRef.current) refImageInputRef.current.value = '';
   450→  }
   451→
   452→  async function handleGenerateImage() {
   453→    setImageError('');
   454→    setGeneratedImage(null);
   455→    setIsGeneratingImage(true);
   456→    try {
   457→      const apiFn = tool.imageEndpoint === 'generate' ? generateImage : generateLogoImage;
   458→      const { imageUrl } = await apiFn({ ...inputs, _language: i18n.language });
   459→      setGeneratedImage(imageUrl);
   460→    } catch (err) {
   461→      setImageError(err.message || 'Failed to generate image');
   462→    } finally {
   463→      setIsGeneratingImage(false);
   464→    }
   465→  }
   466→
   467→  function stripMarkdown(text) {
   468→    return text
   469→      .replace(/```[\w]*\n?([\s\S]*?)```/g, '$1')
   470→      .replace(/`([^`]+)`/g, '$1')
   471→      .replace(/^#{1,6}\s+/gm, '')
   472→      .replace(/\*{1,3}([^*\n]+)\*{1,3}/g, '$1')
   473→      .replace(/_{1,3}([^_\n]+)_{1,3}/g, '$1')
   474→      .replace(/~~([^~]+)~~/g, '$1')
   475→      .replace(/!\[([^\]]*)\]\([^)]+\)/g, '')
   476→      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
   477→      .replace(/^>\s+/gm, '')
   478→      .replace(/^[-*_]{3,}\s*$/gm, '')
   479→      .replace(/^\|[-| :]+\|$/gm, '')
   480→      .replace(/^\|(.+)\|$/gm, (_, cells) =>
   481→        cells.split('|').map(c => c.trim()).filter(Boolean).join('  '))
   482→      .replace(/\n{3,}/g, '\n\n')
   483→      .trim();
   484→  }
   485→
   486→  async function handleCopy() {
   487→    if (!output) return;
   488→    await navigator.clipboard.writeText(stripMarkdown(output));
   489→    setCopied(true);
   490→    setTimeout(() => setCopied(false), 2000);
   491→  }
   492→
   493→  function handleClear() {
   494→    setOutput('');
   495→    setError('');
   496→    setInputs({});
   497→    finalOutputRef.current = '';
   498→  }
   499→
   500→  function extractJson(text) {
   501→    const match = text.match(/```json\s*([\s\S]*?)```/);
   502→    return match ? match[1].trim() : null;
   503→  }
   504→
   505→  function handleDownloadJson() {
   506→    const json = extractJson(output);
   507→    if (!json) return;
   508→    const blob = new Blob([json], { type: 'application/json' });
   509→    const url = URL.createObjectURL(blob);
   510→    const a = document.createElement('a');
   511→    a.href = url;
   512→    a.download = `${tool.id}.json`;
   513→    a.click();
   514→    URL.revokeObjectURL(url);
   515→  }
   516→
   517→  function saveToHistory(queryInputs, queryOutput) {
   518→    if (!tool?.id || !queryOutput) return;
   519→    const entry = { id: Date.now(), timestamp: new Date().toISOString(), inputs: queryInputs, output: queryOutput };
   520→    const key = `gormaran_history_${tool.id}`;
   521→    const existing = (() => { try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch { return []; } })();
   522→    const updated = [entry, ...existing].slice(0, 10);
   523→    localStorage.setItem(key, JSON.stringify(updated));
   524→    setHistory(updated);
   525→    // Persist to Firestore if logged in
   526→    if (currentUser) {
   527→      addDoc(collection(db, 'users', currentUser.uid, 'history'), {
   528→        toolId: tool.id, toolName: tool.name, categoryId,
   529→        inputs: queryInputs, output: queryOutput,
   530→        createdAt: serverTimestamp(),
   531→      }).catch(console.error);
   532→    }
   533→  }
   534→
   535→  async function loadTemplates() {
   536→    try {
   537→      const q = query(
   538→        collection(db, 'users', currentUser.uid, 'templates'),
   539→        where('toolId', '==', tool.id),
   540→        orderBy('createdAt', 'desc')
   541→      );
   542→      const snap = await getDocs(q);
   543→      setTemplates(snap.docs.map(d => ({ id: d.id, ...d.data() })));
   544→    } catch { setTemplates([]); }
   545→  }
   546→
   547→  async function saveTemplate() {
   548→    if (!templateName.trim() || !currentUser) return;
   549→    setSavingTemplate(true);
   550→    try {
   551→      const cleanInputs = Object.fromEntries(
   552→        Object.entries(inputs).filter(([k]) => !k.startsWith('_'))
   553→      );
   554→      const docRef = await addDoc(collection(db, 'users', currentUser.uid, 'templates'), {
   555→        name: templateName.trim(), toolId: tool.id, toolName: tool.name, categoryId,
   556→        inputs: cleanInputs, createdAt: serverTimestamp(),
   557→      });
   558→      setTemplates(prev => [{ id: docRef.id, name: templateName.trim(), inputs: cleanInputs }, ...prev]);
   559→      setTemplateName('');
   560→      setShowSaveTemplate(false);
   561→    } catch (e) { console.error(e); }
   562→    finally { setSavingTemplate(false); }
   563→  }
   564→
   565→  async function deleteTemplate(templateId) {
   566→    try {
   567→      await deleteDoc(doc(db, 'users', currentUser.uid, 'templates', templateId));
   568→      setTemplates(prev => prev.filter(t => t.id !== templateId));
   569→    } catch (e) { console.error(e); }
   570→  }
