/* ── n8n Chat Widget ── */
.n8n-chat {
  display: flex;
  flex-direction: column;
  gap: 0;
  background: var(--bg-surface);
  border: 1px solid var(--border-color);
  border-radius: var(--border-radius-xl);
  overflow: hidden;
  min-height: 420px;
  max-height: 520px;
}

.n8n-chat__messages {
  flex: 1;
  overflow-y: auto;
  padding: 1.25rem;
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
}

.n8n-chat__msg {
  display: flex;
  align-items: flex-end;
  gap: 0.5rem;
}

.n8n-chat__msg--user { flex-direction: row-reverse; }

.n8n-chat__msg-content {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  max-width: 74%;
}

.n8n-chat__avatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background: var(--gradient-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.75rem;
  flex-shrink: 0;
}

.n8n-chat__download {
  align-self: flex-start;
  background: var(--bg-surface-3);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  color: var(--text-secondary);
  font-size: 0.8rem;
  padding: 0.3rem 0.75rem;
  cursor: pointer;
  transition: border-color var(--transition), color var(--transition);
  font-family: var(--font-sans);
}
.n8n-chat__download:hover {
  border-color: var(--color-primary);
  color: var(--text-primary);
}

.n8n-chat__bubble {
  max-width: 100%;
  padding: 0.65rem 0.9rem;
  border-radius: 16px;
  font-size: 0.9rem;
  line-height: 1.5;
  white-space: pre-wrap;
}

.n8n-chat__msg--assistant .n8n-chat__bubble {
  background: var(--bg-surface-2);
  border: 1px solid var(--border-color);
  border-bottom-left-radius: 4px;
  color: var(--text-primary);
}

.n8n-chat__msg--user .n8n-chat__bubble {
  background: var(--gradient-primary);
  border-bottom-right-radius: 4px;
  color: #fff;
  max-width: 74%;
}

.n8n-chat__bubble--typing {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 0.75rem 0.9rem;
}

.n8n-chat__bubble--typing span {
  display: block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-muted);
  animation: n8n-bounce 1.2s infinite ease-in-out;
}
.n8n-chat__bubble--typing span:nth-child(2) { animation-delay: 0.2s; }
.n8n-chat__bubble--typing span:nth-child(3) { animation-delay: 0.4s; }

@keyframes n8n-bounce {
  0%, 60%, 100% { transform: translateY(0); }
  30% { transform: translateY(-5px); }
}

.n8n-chat__examples {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  padding: 0.75rem 1.25rem;
  border-top: 1px solid var(--border-color);
}

.n8n-chat__chip {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: 20px;
  color: var(--text-secondary);
  font-size: 0.775rem;
  padding: 0.3rem 0.75rem;
  cursor: pointer;
  transition: border-color var(--transition), color var(--transition);
  font-family: var(--font-sans);
}
.n8n-chat__chip:hover:not(:disabled) {
  border-color: var(--color-primary);
  color: var(--text-primary);
}
.n8n-chat__chip:disabled { opacity: 0.4; cursor: not-allowed; }

.n8n-chat__input-row {
  display: flex;
  gap: 0.6rem;
  padding: 0.85rem 1.25rem;
  border-top: 1px solid var(--border-color);
}

.n8n-chat__input {
  flex: 1;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-color);
  border-radius: 10px;
  color: var(--text-primary);
  font-size: 0.9rem;
  padding: 0.6rem 0.9rem;
  outline: none;
  transition: border-color var(--transition);
  font-family: var(--font-sans);
}
.n8n-chat__input::placeholder { color: var(--text-muted); }
.n8n-chat__input:focus { border-color: var(--color-primary); }
.n8n-chat__input:disabled { opacity: 0.5; cursor: not-allowed; }

.n8n-chat__send {
  background: var(--gradient-primary);
  color: #fff;
  border: none;
  border-radius: 10px;
  padding: 0.6rem 1.2rem;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: opacity var(--transition);
  font-family: var(--font-sans);
}
.n8n-chat__send:disabled { opacity: 0.4; cursor: not-allowed; }
.n8n-chat__send:not(:disabled):hover { opacity: 0.85; }

